import{_ as o,o as a,c as t,ag as i}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"ADR-0008: QiLabs as Canonical Local Workstation Root","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0008_qilabs_root.md","filePath":"10_core/10_governance/50_decisions/adr-0008_qilabs_root.md"}'),c={name:"10_core/10_governance/50_decisions/adr-0008_qilabs_root.md"};function n(r,e,s,l,d,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-0008-qilabs-as-canonical-local-workstation-root" tabindex="-1">ADR-0008: QiLabs as Canonical Local Workstation Root <a class="header-anchor" href="#adr-0008-qilabs-as-canonical-local-workstation-root" aria-label="Permalink to &quot;ADR-0008: QiLabs as Canonical Local Workstation Root&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The architecture historically defined the developer/operator machine with a local state rooted at <code>C:/QiData/</code>. However, the ecosystem has evolved to encompass <code>QiArchive</code> (the system/spine concept) as well as the monorepo platform (<code>QiOne</code>). These are not simply sibling root folders but need to be part of a structured canonical machine-local ecosystem.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li><code>QiLabs</code> will serve as the canonical machine root for local workstations.</li><li><code>QiData</code> (the state directory) will live directly under <code>QiLabs</code> (<code>C:/QiLabs/QiData</code>).</li><li><code>_QiOne_MonoRepo</code> will live under <code>QiLabs</code> (<code>C:/QiLabs/_QiOne_MonoRepo</code>).</li><li><code>QiArchive</code> represents a system/spine concept, not a literal sibling root directory.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>This aligns the workstation filesystem with the system architecture model. By encapsulating everything within <code>QiLabs</code>, <code>QiOne</code> functions fully as the monorepo platform and <code>QiData</code> functions as local state, while preventing fragmentation across the machine.</p>',7)])])}const m=o(c,[["render",n]]);export{p as __pageData,m as default};
